(function(){'use strict';document.addEventListener('DOMContentLoaded',function(){if(typeof Splide==="undefined"){return}var e=document.querySelector('[data-labs-carousel]');if(!e){return}var s=new Splide(e,{type:'slide',perPage:8,perMove:1,gap:'14px',arrows:false,pagination:false,breakpoints:{1024:{perPage:6,gap:'12px'},767:{perPage:4,gap:'6px'}}});s.mount();var p=document.querySelector('[data-labs-prev]'),n=document.querySelector('[data-labs-next]');if(p){p.addEventListener('click',function(){s.go('<')})}if(n){n.addEventListener('click',function(){s.go('>')})}})}());